function img = fImgSmooth9(img)%% image smoothing with neigbour pixel%% smtImg: smoothed image%% img: input image%% Written by Kei Nakamura% % 2014/7/22 ver.1: Created %% used in% bellaFrogFitTest%% main body[imgY,imgX] = size(img);    % image size x and ypadImg = [zeros(1,imgX+2);zeros(imgY,1),img,zeros(imgY,1);zeros(1,imgX+2)];img(:,:) = img+0.5*( padImg(2:end-1,1:end-2)...  % left    +padImg(2:end-1,3:end)... % right    +padImg(1:end-2,2:end-1)... % up    +padImg(3:end,2:end-1) );  % downimg(:,:) = img+0.5/sqrt(2)*( padImg(1:end-2,1:end-2)...  % topleft    +padImg(1:end-2,3:end)... % top right    +padImg(3:end,1:end-2)... % bottom left    +padImg(3:end,3:end));  % bottom rightimg(:,:) = img/(3+2/sqrt(2));
